operations.query:
query RepositoryVariableNameCollisions ($variables_: String!, $octoql: String!, $context: String!, $ctx_: String!, $client_: String!, $err_: String!) {
	primary: repository(owner: $octoql, name: $context) {
		nameWithOwner
	}
	variables: repository(owner: $variables_, name: $client_) {
		nameWithOwner
	}
	errors: repository(owner: $err_, name: $octoql) {
		nameWithOwner
	}
	contextName: repository(owner: $ctx_, name: $context) {
		nameWithOwner
	}
}
